// DPI-C function signature matching the SystemVerilog call
// N: Dimension (e.g., 4 for 4x4 matrix)
// A: Pointer to the first matrix (A)
// B: Pointer to the second matrix (B)
// C: Pointer to the result matrix (C)
void compute_matrix_product(int N, double *A, double *B, double *C) {
    int i, j, k;

    // Matrix multiplication: C = A * B
    // C[i][j] = Sum(A[i][k] * B[k][j])

    // We iterate over the indices corresponding to the flattened array structure:
    // Index = row * N + col

    for (i = 0; i < N; i++) { // Row of C (and A)
        for (j = 0; j < N; j++) { // Column of C (and B)
            double sum = 0.0;
            for (k = 0; k < N; k++) { // Summation index
                // A[i*N + k] corresponds to A[i][k]
                // B[k*N + j] corresponds to B[k][j]
                sum += A[i * N + k] * B[k * N + j];
            }
            // Store the result in C[i*N + j]
            C[i * N + j] = sum;
        }
    }

    // Note: The C function performs the calculation directly and updates the memory pointed to by C.
}

