#include <stdio.h>
#include <stdint.h>

// DPI function signature matching the SV call:
// int calculate_crc(logic [31:0] current_crc, logic [7:0] data_in, logic [31:0] poly)
// Note: We use uint32_t for 32-bit registers and uint8_t for 8-bit data.
// The return type (int) is used only to satisfy the DPI signature, 
// but the actual result is returned via the return value.

int calculate_crc(uint32_t current_crc, uint8_t data_in, uint32_t poly) {
    uint32_t crc = current_crc;
    uint32_t temp_data = data_in;

    // Replicating the 8-bit loop logic
    for (int i = 0; i < 8; i++) {
        // Check the LSB of the current CRC state XORed with the current data bit
        // The original logic used data_in[i] which implies shifting the data bit.
        // Since the loop runs 8 times, we use the i-th bit of the input data.
        // (data_in >> i) & 1 is equivalent to data_in[i]

        if (((crc & 1) ^ ((temp_data >> i) & 1)) == 1) {
            // If XOR result is 1: crc = (crc >> 1) ^ poly
            crc = (crc >> 1) ^ poly;
        } else {
            // If XOR result is 0: crc = crc >> 1
            crc = (crc >> 1);
        }
    }

    // Return the final calculated CRC value
    return (int)crc; 
}

